def check(s1: str, s2: str) -> bool:
    n = len(s1)
    m = len(s2)
    # Create a DP table initialized to False. Dimensions: (n+1) x (m+1)
    dp = [[False] * (m + 1) for _ in range(n + 1)]
    dp[0][0] = True  # Starting state
    for i in range(n):
        for j in range(m + 1):
            if dp[i][j]:
                # If we can transform s1[i] to uppercase and match the current letter in s2
                if j < m and s1[i].upper() == s2[j]:
                    dp[i + 1][j + 1] = True
                # If s1[i] is lowercase, we have the option to delete it
                if not s1[i].isupper():
                    dp[i + 1][j] = True
    return dp[n][m]

