def findSubsequenceCount(S: str, T: str) -> int:
    m, n = len(T), len(S)
    if m > n:
        return 0
    # Initialize the matrix with zeros: (m+1) rows and (n+1) columns.
    mat = [[0] * (n + 1) for _ in range(m + 1)]
    # Base case: An empty T is a subsequence of any prefix of S.
    for j in range(n + 1):
        mat[0][j] = 1
    # Base case: For any non-empty T, there is 0 chance it is a subsequence of an empty S.
    for i in range(1, m + 1):
        mat[i][0] = 0
    # Build the matrix using dynamic programming.
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if T[i - 1] != S[j - 1]:
                mat[i][j] = mat[i][j - 1]
            else:
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1]
    return mat[m][n]

