def numOfIncSubseqOfSizeK(arr, n, k):
    # Create a dp table with k rows and n columns, initialized to 0
    dp = [[0] * n for _ in range(k)]
    # Every element is a subsequence of size 1 by itself
    for i in range(n):
        dp[0][i] = 1
    # Build the dp table for subsequences of length from 2 to k (indexed by l)
    for l in range(1, k):
        # For each subsequence length 'l+1', the starting index in arr must be at least l
        for i in range(l, n):
            dp[l][i] = 0
            # Check all previous elements that can extend an increasing subsequence
            for j in range(l - 1, i):
                if arr[j] < arr[i]:
                    dp[l][i] += dp[l - 1][j]
    # Sum up all subsequences of length exactly k (stored in dp[k-1])
    total = sum(dp[k - 1][i] for i in range(k - 1, n))
    return total

