def countP(n, k):
    # Create a 2D list initialized to 0
    dp = [[0] * (k + 1) for _ in range(n + 1)]
    # Initialize the first column (dp[i][0] = 0 for all i); already 0 but including for clarity
    for i in range(n + 1):
        dp[i][0] = 0
    # Initialize the first row (dp[0][j] = 0 for all j); already 0 but including for clarity
    for j in range(k + 1):
        dp[0][j] = 0
    # Fill in dp table according to the recurrence:
    for i in range(1, n + 1):
        for j in range(1, k + 1):
            if j == 1 or i == j:
                dp[i][j] = 1
            else:
                dp[i][j] = j * dp[i - 1][j] + dp[i - 1][j - 1]
    return dp[n][k]

