def countPS(s: str, n: int) -> int:
    # Initialize dp and P tables with zeros and False respectively
    dp = [[0 for _ in range(n)] for _ in range(n)]
    P = [[False for _ in range(n)] for _ in range(n)]
    # Every single character is a palindrome
    for i in range(n):
        P[i][i] = True
    # Check for palindromic substrings of length 2.
    for i in range(n - 1):
        if s[i] == s[i + 1]:
            P[i][i + 1] = True
            dp[i][i + 1] = 1
    # Check for lengths greater than 2. gap is length-1
    for gap in range(2, n):
        for i in range(n - gap):
            j = i + gap
            # If current characters match and the inner substring is a palindrome
            if s[i] == s[j] and P[i + 1][j - 1]:
                P[i][j] = True
            # Count palindromic substrings in substring s[i...j]
            if P[i][j]:
                dp[i][j] = dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1]
            else:
                dp[i][j] = dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1]
    return dp[0][n - 1]

