def countPS(s: str) -> int:
    N = len(s)
    # Initialize a 2D list with dimensions N x N filled with 0
    cps = [[0] * N for _ in range(N)]
    # All substrings of length 1 are palindromic (single character)
    for i in range(N):
        cps[i][i] = 1
    # L is the length of the substring
    for L in range(2, N + 1):
        # i is the starting index of the substring
        for i in range(N - L + 1):
            k = L + i - 1  # Ending index of the substring
            if s[i] == s[k]:
                cps[i][k] = cps[i][k - 1] + cps[i + 1][k] + 1
            else:
                cps[i][k] = cps[i][k - 1] + cps[i + 1][k] - cps[i + 1][k - 1]
    return cps[0][N - 1]

