    count = 1
    if length == 1:
        return count
    # Check the first two characters
    if s[0] == s[1]:
        count *= 1
    else:
        count *= 2
    # Iterate through the middle of the string
    for j in range(1, length - 1):
        if s[j] == s[j - 1] and s[j] == s[j + 1]:
            count *= 1
        elif s[j] == s[j - 1] or s[j] == s[j + 1] or s[j - 1] == s[j + 1]:
            count *= 2
        else:
