def findWays(m, n, x):
    # Create a 2D list initialized with 0's.
    # We use (n+1) rows and (x+1) columns since the C++ code uses 1-indexing for the first dimension.
    dp = [[0] * (x + 1) for _ in range(n + 1)]
    # Base case: For 1 group (i = 1), set dp[1][j] = 1 for j from 1 up to min(m, x)
    for j in range(1, min(m, x) + 1):
        dp[1][j] = 1
    # Build the table for i from 2 to n
    for i in range(2, n + 1):
        for j in range(1, x + 1):
            # k goes from 1 up to min(m, j-1) inclusive.
            for k in range(1, min(m, j - 1) + 1):
