def numberofways(n, m):
    # Create a 2D DP table with dimensions (n + 2) x (n + 2) initialized to 0.
    dp = [[0] * (n + 2) for _ in range(n + 2)]
    # Base case: there's one way to get a sum of 0.
    dp[0][n + 1] = 1
    # Process in reverse order from n down to m.
    for k in range(n, m - 1, -1):
        for i in range(n + 1):
            dp[i][k] = dp[i][k + 1]
            if i >= k:
                dp[i][k] += dp[i - k][k]
    return dp[n][m]

