def discreteLogarithm(a, b, m):
    n = int(math.sqrt(m)) + 1
    # Compute a^n mod m
    an = 1
    for i in range(n):
        an = (an * a) % m
    # Precompute values of (a^n)^i mod m
    value = {}
    cur = an
    for i in range(1, n + 1):
        if cur not in value:
            value[cur] = i
        cur = (cur * an) % m
    # Search for an answer by trying smaller exponents
    cur = b
    for i in range(n + 1):
        if cur in value:
            ans = value[cur] * n - i
            if ans < m:
                return ans
        cur = (cur * a) % m
    return -1

