def lps(s: str) -> int:
    n = len(s)
    # Create a 2D list (matrix) initialized with zeros
    L = [[0] * n for _ in range(n)]
    # Every individual character is a palindrome of length 1
    for i in range(n):
        L[i][i] = 1
    # cl is the length of the substring 
    for cl in range(2, n + 1):
        for i in range(n - cl + 1):
            j = i + cl - 1
            if s[i] == s[j]:
                if cl == 2:
                    L[i][j] = 2
                else:
                    L[i][j] = L[i + 1][j - 1] + 2
            else:
                L[i][j] = max(L[i][j - 1], L[i + 1][j])
    return L[0][n - 1]

