def lbs(arr):
    n = len(arr)
    # Compute longest increasing subsequence (LIS) for each element
    lis = [1] * n
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and lis[i] < lis[j] + 1:
                lis[i] = lis[j] + 1
    # Compute longest decreasing subsequence (LDS) for each element
    lds = [1] * n
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j] and lds[i] < lds[j] + 1:
                lds[i] = lds[j] + 1
    # The maximum length of the bitonic subsequence
    maximum = lis[0] + lds[0] - 1
    for i in range(1, n):
        if lis[i] + lds[i] - 1 > maximum:
            maximum = lis[i] + lds[i] - 1
    return maximum

