def minPalPartion(s: str) -> int:
    n = len(s)
    # Initialize 2D arrays for palindromic checks and cut counts.
    P = [[False] * n for _ in range(n)]
    C = [[0] * n for _ in range(n)]
    # Every single character is a palindrome, and no cut is needed.
    for i in range(n):
        P[i][i] = True
        C[i][i] = 0
    # L is the length of the substring
    for L in range(2, n + 1):
        for i in range(n - L + 1):
            j = i + L - 1
            if L == 2:
                P[i][j] = (s[i] == s[j])
            else:
                P[i][j] = (s[i] == s[j]) and P[i+1][j-1]
            if P[i][j]:
                C[i][j] = 0
            else:
                # Set initial value to a very large number
                C[i][j] = float('inf')
                for k in range(i, j):
                    C[i][j] = min(C[i][j], C[i][k] + C[k+1][j] + 1)
    return C[0][n - 1]

