def isSubsetSum(arr, n, target):
    # Create a 2D list to store the subset table.
    # The table has dimensions (n+1) x (target+1)
    subset = [[False] * (target + 1) for _ in range(n + 1)]
    # If sum is 0, then answer is true for all items.
    for i in range(n + 1):
        subset[i][0] = True
    # If there are no items and the sum is not 0, then answer is false.
    # This initialization is already covered by the False default value.
    # Fill the subset table in a bottom-up manner.
    for i in range(1, n + 1):
        for j in range(1, target + 1):
            if j < arr[i - 1]:
                subset[i][j] = subset[i - 1][j]
            else:
