def subsequence(s, k):
    n = len(s)
    last = 0
    result = []
    # Traverse letters from 'z' down to 'a'
    for ch in range(ord('z'), ord('a') - 1, -1):
        char = chr(ch)
        # Count occurrences of the current character in s starting from index 'last'
        cnt = sum(1 for i in range(last, n) if s[i] == char)
        # If there are at least k occurrences, include all occurrences from 'last'
        if cnt >= k:
            new_last = last
            for i in range(last, n):
                if s[i] == char:
                    result.append(char)
                    new_last = i
            last = new_last  # update last to the last found index
    return ''.join(result)

