        return "Not possible"
    # Second pass: maximize the palindrome.
    l, r = 0, n - 1
    while l <= r:
        if l == r:
            # Middle element in an odd-length palindrome.
            if k > 0:
                palin[l] = '9'
        if palin[l] < '9':
            # If both digits are already the same as original,
            # it costs 2 changes to upgrade them to '9'
            if k >= 2 and palin[l] == s[l] and palin[r] == s[r]:
