def maxAverageOfPath(cost, N):
    # Create a DP table of size (N+1) x (N+1) initialized with zeros.
    dp = [[0] * (N + 1) for _ in range(N + 1)]
    # Base initialization: the first cell is the same as cost[0][0]
    dp[0][0] = cost[0][0]
    # Fill the first column (only vertical moves possible)
    for i in range(1, N):
        dp[i][0] = dp[i - 1][0] + cost[i][0]
    # Fill the first row (only horizontal moves possible)
    for j in range(1, N):
        dp[0][j] = dp[0][j - 1] + cost[0][j]
    # Fill the rest of the dp table.
    # Note: In the original C++ code, the inner loop iterates j from 1 to N inclusive.
    # However, since our cost matrix is indexed from 0 to N-1, we loop j from 1 to N-1.
    for i in range(1, N):
        for j in range(1, N):
            dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j]
    # Calculate the average by dividing the maximum cost path sum by the path length (2N-1)
    return dp[N - 1][N - 1] / (2 * N - 1)

