def simplify(expr: str) -> str:
    res = []
    stack = [0]  # 0 means positive context, 1 means negative context
    i = 0
    n = len(expr)
    while i < n:
        ch = expr[i]
        if ch == '+':
            if stack[-1] == 1:
                res.append('-')
            else:
                res.append('+')
        elif ch == '-':
            if stack[-1] == 1:
                res.append('+')
            else:
                res.append('-')
        elif ch == '(' and i > 0:
            # Only process the parenthesis if it's not the very first character.
            if expr[i - 1] == '-':
                # Flip the sign: if currently negative, new context becomes positive (0); if positive, becomes negative (1)
                new_context = 0 if stack[-1] == 1 else 1
                stack.append(new_context)
            elif expr[i - 1] == '+':
                stack.append(stack[-1])
            # Note: We're not appending '(' to the result.
        elif ch == ')':
            if stack:
                stack.pop()
        else:
            res.append(ch)
        i += 1
    return ''.join(res)

