def knapSack(val, wt, n, W):
    # Create a 2 x (W+1) matrix filled with zeros
    mat = [[0] * (W + 1) for _ in range(2)]
    i = 0
    while i < n:
        j = 0
        if i % 2 != 0:
            # For odd index i, update row 1 using row 0
            while True:
                j += 1
                if j > W:
                    break
                # Check condition and update accordingly.
                if wt[i] <= j and j - wt[i] < W:
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j])
                else:
                    mat[1][j] = mat[0][j]
        else:
            # For even index i, update row 0 using row 1
            while True:
                j += 1
                if j > W:
