                if wt[i] <= j and j - wt[i] < W:
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j])
                else:
                    mat[0][j] = mat[1][j]
        i += 1
    # Return the optimal value depending on the parity of n.
