def sumofsquare(n):
    # Initialize a 2D list with dimensions (n+1) x (n+1) filled with zeros.
    C = [[0] * (n + 1) for _ in range(n + 1)]
    # Build Pascal's triangle
    for i in range(n + 1):
        # j runs from 0 to min(i, n) which is just i since i <= n
        for j in range(min(i, n) + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
    # Calculate the sum of squares of the binomial coefficients in the nth row
    total = sum(C[n][i] * C[n][i] for i in range(n + 1))
    return total

