def offeringNumber(n, templeHeight):
    total = 0
    for i in range(n):
        left = 0
        right = 0
        # Check left side
        j = i - 1
        while j >= 0:
            if templeHeight[j] < templeHeight[j + 1]:
                left += 1
                j -= 1
            else:
                break
        # Check right side
        j = i + 1
        while j < n:
            if templeHeight[j] < templeHeight[j - 1]:
                right += 1
                j += 1
            else:
                break
        total += max(left, right) + 1
    return total

