def countUnique(mat, n, m):
    # Initialize row and column sums with 0's.
    rowsum = [0] * n
    colsum = [0] * m
    # First pass to calculate the sum for each row and column.
    for i in range(n):
        for j in range(m):
            if mat[i][j]:
                rowsum[i] += 1
                colsum[j] += 1
    uniquecount = 0
    # Second pass to count unique elements.
    for i in range(n):
        for j in range(m):
            if mat[i][j] and rowsum[i] == 1 and colsum[j] == 1:
                uniquecount += 1
    return uniquecount

